"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["682440"],{96535(e){e.exports=JSON.parse('{"tag":{"label":"health","permalink":"/dst-api-webdocs/docs/tags/health","allTagsPath":"/dst-api-webdocs/docs/tags","count":19,"items":[{"id":"game-scripts/prefabs/alterguardian_phase3","title":"Alterguardian Phase3","description":"Serves as the final phase boss entity for the Alterguardian, handling combat logic, health regeneration, trap spawning, music events, and loot drops during its terminal phase in the game.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/alterguardian_phase3"},{"id":"game-scripts/widgets/bloodover","title":"Bloodover","description":"Renders a dynamic visual overlay on the screen when the owner entity is in critical health states such as freezing, overheating, starving, or suffering from lunar burn.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/bloodover"},{"id":"game-scripts/widgets/boatmeter","title":"Boatmeter","description":"Displays a boat\'s health status and leak state in the UI, updating dynamically during gameplay.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/boatmeter"},{"id":"game-scripts/components/dockmanager","title":"Dockmanager","description":"Manages the creation, destruction, health tracking, and structural integrity of monkey docks on Monkey Island maps.","permalink":"/dst-api-webdocs/docs/game-scripts/components/dockmanager"},{"id":"game-scripts/prefabs/halloweenpotion_buffs","title":"Halloweenpotion Buffs","description":"Creates and manages buff entities that apply periodic health/sanity restoration or bravery effects when attached via the halloween potion items.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/halloweenpotion_buffs"},{"id":"game-scripts/components/health_replica","title":"Health Replica","description":"Manages network-synchronized health state for player entities, mirroring properties from the master-side Health component for client-side UI and logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/health_replica"},{"id":"game-scripts/widgets/healthbadge","title":"Healthbadge","description":"UI widget that displays player health status, effigy indicators, buff icons, and WX-78 shield visualization on the HUD.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/healthbadge"},{"id":"game-scripts/components/healthbar","title":"Healthbar","description":"Renders a visual health bar and percentage label above an entity, updating in response to health changes.","permalink":"/dst-api-webdocs/docs/game-scripts/components/healthbar"},{"id":"game-scripts/prefabs/healthregenbuff","title":"Healthregenbuff","description":"A temporary entity that periodically restores health to a target using jellybean-style regen logic, stopping automatically if the target dies or becomes a ghost.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/healthregenbuff"},{"id":"game-scripts/components/healthsyncer","title":"Healthsyncer","description":"Synchronizes health status and percentage between server and client, tracking health regen/degen sources for UI indicators.","permalink":"/dst-api-webdocs/docs/game-scripts/components/healthsyncer"},{"id":"game-scripts/components/healthtrigger","title":"Healthtrigger","description":"Triggers custom callbacks when an entity\'s health percentage crosses specified thresholds during damage or healing events.","permalink":"/dst-api-webdocs/docs/game-scripts/components/healthtrigger"},{"id":"game-scripts/prefabs/hermitcrabtea_defs","title":"Hermitcrabtea Defs","description":"Defines tea ingredients and their associated buffs for the Hermit Crab Teapot prefab.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hermitcrabtea_defs"},{"id":"game-scripts/components/maxhealer","title":"Maxhealer","description":"Applies a health penalty reduction to a target entity when consumed, typically used for revive-like consumable items.","permalink":"/dst-api-webdocs/docs/game-scripts/components/maxhealer"},{"id":"game-scripts/components/oldager","title":"Oldager","description":"Manages time-based aging mechanics by converting accumulated damage into health damage over time, simulating biological aging effects on entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/oldager"},{"id":"game-scripts/widgets/pethealthbadge","title":"Pethealthbadge","description":"Displays a pet\'s health as a badge with optional dual buff icons and directional health-change indicators.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/pethealthbadge"},{"id":"game-scripts/widgets/sanitybadge","title":"Sanitybadge","description":"Renders the sanity/lunacy indicator UI widget, including animations for sanity changes, rate direction, and ghost drain state.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/sanitybadge"},{"id":"game-scripts/widgets/statusdisplays_lavaarena","title":"Statusdisplays Lavaarena","description":"Manages health and pet health status displays for the Lava Arena minigame, including dynamic UI updates, visibility toggling, and health pulse animations.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/statusdisplays_lavaarena"},{"id":"game-scripts/widgets/teammatehealthbadge","title":"Teammatehealthbadge","description":"Renders a player\'s health and optional pet health as a UI badge in Lava Arena scenarios.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/teammatehealthbadge"},{"id":"game-scripts/widgets/teamstatusbars","title":"Teamstatusbars","description":"Manages and displays health status bars for teammates (other players and their pets) in the UI during multiplayer sessions.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/teamstatusbars"}],"unlisted":false}}')}}]);